const input = $json || {};
const user_id = String(input.user_id || '');
if (!user_id) return [{ json: { ok:false, error:'user_id obrigatorio' } }];
const mode = (['reactivation','mixed'].includes(input.mode)) ? input.mode : 'reactivation';
const uf  = input.uf ? String(input.uf).toUpperCase().slice(0,2) : null;
const cid = input.cidade ? String(input.cidade).toUpperCase() : null;
const max_stops = Math.max(1, Math.min(20, +input.max_stops || 8));
const origin_lat = Number.isFinite(+input.origin_lat) ? +input.origin_lat : -23.6884;
const origin_lng = Number.isFinite(+input.origin_lng) ? +input.origin_lng : -46.6178;
const name = input.name ? String(input.name) : ('Roteiro IA ' + new Date().toLocaleDateString('pt-BR'));
let exclude_codes = [];
try {
  const raw = input.exclude_codes;
  const arr = Array.isArray(raw) ? raw : (typeof raw === 'string' ? JSON.parse(raw || '[]') : []);
  exclude_codes = (arr || []).map(c => String(c).trim()).filter(Boolean).slice(0, 200);
} catch (e) { exclude_codes = []; }
return [{ json: { ok:true, user_id, mode, uf, cid, max_stops, origin_lat, origin_lng, name, exclude_codes } }];

