SELECT jsonb_agg(to_jsonb(c.*)) AS rows FROM castor_route_candidates(
  '{{ $json.user_id }}'::uuid,
  '{{ $json.mode }}',
  {{ $json.uf  ? "'" + $json.uf  + "'" : 'NULL' }},
  {{ $json.cid ? "'" + $json.cid.replace(/'/g, "''") + "'" : 'NULL' }},
  {{ $json.max_stops }}
) c;

parameters.jsCode:
const ctx  = $('Validate').first().json;
let rows = ($input.first() && $input.first().json && $input.first().json.rows) || [];
const _excl = new Set((ctx.exclude_codes || []).map(c => String(c)));
if (_excl.size) {
  rows = rows.filter(r => !_excl.has(String(r.cliente_codigo || r.code || '')));
}
if (!rows.length) {
  return [{ json: { ok:false, error:'sem candidatos elegíveis no escopo (uf/cidade/escopo do vendedor)' } }];
}
function km(lat1,lng1,lat2,lng2){const r=(d)=>d*Math.PI/180;const dlat=r(lat2-lat1)/2,dlng=r(lng2-lng1)/2;const a=Math.sin(dlat)*Math.sin(dlat)+Math.cos(r(lat1))*Math.cos(r(lat2))*Math.sin(dlng)*Math.sin(dlng);return 6371*2*Math.asin(Math.sqrt(a));}
function buildAddress(r){
  const parts = [];
  if (r.a1_end) parts.push(String(r.a1_end).trim());
  const muniEst = [r.a1_mun, r.a1_est].filter(Boolean).join(' - ');
  if (muniEst) parts.push(muniEst);
  if (r.a1_cep) parts.push('CEP ' + String(r.a1_cep).trim());
  return parts.join(', ');
}
const mapped = rows.map(r => {
  const lat = (r.lat != null && r.lat !== '') ? +r.lat : null;
  const lng = (r.lng != null && r.lng !== '') ? +r.lng : null;
  const hasCoord = Number.isFinite(lat) && Number.isFinite(lng);
  return {
    cliente_codigo: r.cliente_codigo, name: r.a1_nome,
    lat: hasCoord ? lat : null,
    lng: hasCoord ? lng : null,
    address: buildAddress(r),
    status_real: r.status_real, urgencia: +r.urgencia_score,
    fat: +r.faturamento_alltime, dias: +r.dias_sem_pedido,
    mun: r.a1_mun, est: r.a1_est, porte: r.porte_efetivo,
    _hasCoord: hasCoord
  };
});
const withCoord = mapped.filter(x => x._hasCoord);
const noCoord   = mapped.filter(x => !x._hasCoord).sort((a,b) => (b.urgencia||0) - (a.urgencia||0));
let curLat = ctx.origin_lat, curLng = ctx.origin_lng, total = 0;
const ordered = [];
const remaining = withCoord.slice();
while (remaining.length) {
  let best = -1, bestD = Infinity;
  for (let i = 0; i < remaining.length; i++) {
    const d = km(curLat, curLng, remaining[i].lat, remaining[i].lng);
    if (d < bestD) { bestD = d; best = i; }
  }
  const nxt = remaining.splice(best, 1)[0];
  total += bestD;
  delete nxt._hasCoord;
  ordered.push(Object.assign({}, nxt, { seq: ordered.length + 1, leg_km: Math.round(bestD*10)/10, cum_km: Math.round(total*10)/10 }));
  curLat = nxt.lat; curLng = nxt.lng;
}
// paradas sem geocode entram no fim, ordenadas por urgência. leg_km/cum_km = null.
noCoord.forEach(nxt => {
  delete nxt._hasCoord;
  ordered.push(Object.assign({}, nxt, { seq: ordered.length + 1, leg_km: null, cum_km: total ? Math.round(total*10)/10 : null }));
});

function wpEnc(s){
  if (Number.isFinite(s.lat) && Number.isFinite(s.lng)) return s.lat + ',' + s.lng;
  return encodeURIComponent(s.address || (s.name + ', ' + (s.mun||'') + ' - ' + (s.est||'')));
}
const originStr = ctx.origin_lat + ',' + ctx.origin_lng;
const wpItems = ordered.slice(0, -1).map(wpEnc);
const destItem = wpEnc(ordered[ordered.length - 1]);
const maps_url = 'https://www.google.com/maps/dir/?api=1&origin=' + originStr + (wpItems.length ? '&waypoints=' + wpItems.join('|') : '') + '&destination=' + destItem;

const urgMed  = Math.round(ordered.reduce((s,x)=>s+(x.urgencia||0),0)/ordered.length);
const fatSum  = ordered.reduce((s,x)=>s+(x.fat||0),0);
const ufs = Array.from(new Set(ordered.map(x=>x.est).filter(Boolean))).join(', ');
const muns = Array.from(new Set(ordered.map(x=>x.mun).filter(Boolean))).slice(0,4).join(', ');
const semGeoNote = noCoord.length
  ? ` ${noCoord.length} parada(s) ficaram sem coordenadas e entraram no fim do roteiro pelo endereço cadastrado — o Maps tenta localizar pelo nome/CEP, mas vale conferir/ajustar manualmente.`
  : '';
const kmStr = total > 0 ? `~${total.toFixed(1)} km` : 'distância não calculada (sem coordenadas)';
const rationale = `Selecionei ${ordered.length} cliente(s) em ${ufs || '—'} (${muns}${ordered.length>4?'…':''}), priorizando maior urgência (score médio ${urgMed}). Faturamento histórico somado dos selecionados: R$ ${fatSum.toLocaleString('pt-BR',{maximumFractionDigits:0})}. Total de ${kmStr} no roteiro otimizado por vizinho mais próximo.${semGeoNote}`;

return [{ json: { ok:true, ordered, total_km: Math.round(total*10)/10, maps_url, rationale, ctx, no_geocode_count: noCoord.length } }];

const r = $input.first().json.result || $input.first().json;
const route_id = (r && r.route_id) || $input.first().json.route_id;
const appended = !!(r && r.appended);
const added_count = (r && r.added_count) || 0;
const d = $('Order & rationale').first().json;
return [{ json: { ok:true, data: { route_id, appended, added_count, name: d.ctx.name, stops: d.ordered, total_km: d.total_km, maps_url: d.maps_url, rationale: d.rationale }, error:null } }];
